const text = String($json.transcript_text || '');
if (!text.trim()) throw new Error('transcript_text is required for extraction');

const findNum = (regex) => {
  const m = text.match(regex);
  return m ? Number(m[1]) : null;
};

const roas = findNum(/ROAS(?: is| at)?\s*([0-9]+(?:\.[0-9]+)?)/i);
const cacPrev = (() => {
  const m = text.match(/CAC rose from \$?([0-9]+(?:\.[0-9]+)?) to \$?([0-9]+(?:\.[0-9]+)?)/i);
  return m ? Number(m[1]) : null;
})();
const cacCurrent = (() => {
  const m = text.match(/CAC rose from \$?([0-9]+(?:\.[0-9]+)?) to \$?([0-9]+(?:\.[0-9]+)?)/i);
  return m ? Number(m[2]) : null;
})();
const spend = findNum(/spend about \$?([0-9]+(?:,[0-9]{3})*(?:\.[0-9]+)?)/i);
const mobileShare = findNum(/([0-9]+(?:\.[0-9]+)?)% of paid traffic is mobile/i);
const checkoutCv = findNum(/Checkout conversion is only ([0-9]+(?:\.[0-9]+)?)%/i);
const aov = findNum(/average order value is \$?([0-9]+(?:\.[0-9]+)?)/i);

const goalRoas = findNum(/ROAS(?: at)? ([0-9]+(?:\.[0-9]+)?)\+/i);
const goalCac = findNum(/CAC below \$?([0-9]+(?:\.[0-9]+)?)/i);

const constraints = [];
if (/small team/i.test(text)) constraints.push('Small team');
if (/one video editor/i.test(text)) constraints.push('One video editor');
if (/no signed UGC creators/i.test(text)) constraints.push('No signed UGC creators yet');

const competitors = [];
const compMatch = text.match(/Competitors[^\n]*\nClient:\s*([^\.]+)/i);
if (compMatch) {
  compMatch[1].split(/,|and/i).map(s => s.trim()).filter(Boolean).forEach(c => competitors.push(c.replace(/\.$/, '')));
}

return [{
  json: {
    ...$json,
    status: 'EXTRACTION_IN_PROGRESS',
    discovery_brief: {
      case_id: $json.case_id,
      problem_summary: 'Meta-to-Shopify efficiency decline with ROAS drop and CAC increase plus conversion leakage.',
      goal_summary: `Target ROAS >= ${goalRoas ?? 'TBD'} and CAC < ${goalCac ?? 'TBD'} in 90 days with repeatable creative testing.`,
      constraints,
      key_metrics: {
        roas_current: roas,
        cac_previous: cacPrev,
        cac_current: cacCurrent,
        monthly_ad_spend: spend,
        mobile_traffic_share_pct: mobileShare,
        checkout_conversion_rate_pct: checkoutCv,
        average_order_value: aov
      },
      competitors
    }
  }
}];
